query:
{
  connectors(
    where: {
      cloudProvider: { eq: "entra" }
      conditionalAccessPolicies_NONE: {
        conditions: {
          NOT: {
            excludeUsers: { eq: [] }
            OR: { includeUsers: { eq: [] }, includeGroups: { eq: [] }, includeRoles: { eq: [] } }
          }
          includeApplications: ["All"]
          clientAppTypes: ["all"]
        }
        grantControls: { builtInControls: ["mfa"] }
      }
    }
  ) {
    ...AssetFragment
  }
}
